import{c as n,S as h,j as i,m as o}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Bộ đề thi","description":"","frontmatter":{},"headers":[],"relativePath":"admin/bo-de-thi.md","filePath":"admin/bo-de-thi.md","lastUpdated":0}'),a={name:"admin/bo-de-thi.md"};function l(r,t,g,c,s,e){return h(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="bo-đe-thi" tabindex="-1">Bộ đề thi <a class="header-anchor" href="#bo-đe-thi" aria-label="Permalink to “Bộ đề thi”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/question/exam-set</code></p><p>Bộ đề thi là <strong>tập hợp nhiều đề thi</strong> được gom lại để gán hàng loạt cho lớp / khóa / học viên. Thay vì gán từng đề một, bạn tạo 1 bộ rồi giao cả bộ — học viên nhận đủ trọn gói.</p><h2 id="khi-nao-dung" tabindex="-1">Khi nào dùng <a class="header-anchor" href="#khi-nao-dung" aria-label="Permalink to “Khi nào dùng”">​</a></h2><ul><li>Tổ chức <strong>kỳ thi thử định kỳ</strong> (vd &quot;Thi thử TNTHPT đợt 1&quot; gồm 4-6 môn).</li><li>Tạo <strong>gói luyện đề</strong> cho cả khóa (vd &quot;Bộ 20 đề luyện thi HSA 2026&quot;).</li><li>Đóng gói <strong>bộ đề ôn cuối kỳ</strong> cho lớp học.</li><li>Chia sẻ một <strong>bộ đề tham khảo</strong> chung cho nhiều giáo viên / nhiều lớp.</li></ul><h2 id="phan-biet" tabindex="-1">Phân biệt <a class="header-anchor" href="#phan-biet" aria-label="Permalink to “Phân biệt”">​</a></h2><table tabindex="0"><thead><tr><th>Khái niệm</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Đề thi đơn lẻ</strong></td><td>1 bài kiểm tra/đề ôn cụ thể</td></tr><tr><td><strong>Bộ đề thi</strong> (trang này)</td><td>Tập hợp nhiều đề trên, đóng gói thành 1 đơn vị giao việc</td></tr><tr><td><strong>Tiêu chí đề thi</strong></td><td>Khuôn dựng đề (không phải đề thật)</td></tr></tbody></table><h2 id="danh-sach-bo-đe" tabindex="-1">Danh sách bộ đề <a class="header-anchor" href="#danh-sach-bo-đe" aria-label="Permalink to “Danh sách bộ đề”">​</a></h2><p>Cột chính:</p><table tabindex="0"><thead><tr><th>Cột</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td>Tên bộ</td><td>Vd &quot;Thi thử TNTHPT đợt 1 - 2026&quot;</td></tr><tr><td>Loại bộ</td><td>Bộ đề HSA / TSA / TNTHPT / Hỗn hợp / Theo môn</td></tr><tr><td>Số đề trong bộ</td><td></td></tr><tr><td>Tổng số câu</td><td></td></tr><tr><td>Đối tượng đã gán</td><td>Số lớp / khóa / học viên đã nhận bộ</td></tr><tr><td>Trạng thái</td><td>Công khai / Nháp / Ẩn</td></tr><tr><td>Người tạo</td><td></td></tr></tbody></table><h3 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h3><ul><li>Theo <strong>Loại bộ</strong>.</li><li>Theo <strong>Trạng thái</strong>.</li><li>Theo <strong>Người tạo</strong>.</li><li>Tìm kiếm theo <strong>Tên bộ</strong>.</li></ul><h2 id="tao-moi-bo-đe" tabindex="-1">Tạo mới bộ đề <a class="header-anchor" href="#tao-moi-bo-đe" aria-label="Permalink to “Tạo mới bộ đề”">​</a></h2><ol><li>Bấm <strong>Thêm mới</strong>.</li><li>Khai báo thông tin chung: <ul><li><strong>Tên bộ</strong> (vd &quot;Thi thử TNTHPT đợt 1 - 2026&quot;).</li><li><strong>Loại bộ</strong>: HSA / TSA / TNTHPT / Hỗn hợp / Theo môn.</li><li><strong>Mô tả</strong> ngắn (hiển thị cho học viên).</li><li><strong>Thời gian mở/đóng</strong> (tùy chọn): khoảng thời gian học viên được làm bộ.</li></ul></li><li>Bấm <strong>Lưu</strong> để tạo bộ trống.</li></ol><h2 id="them-đe-vao-bo" tabindex="-1">Thêm đề vào bộ <a class="header-anchor" href="#them-đe-vao-bo" aria-label="Permalink to “Thêm đề vào bộ”">​</a></h2><ol><li>Mở chi tiết bộ đề.</li><li>Vào tab <strong>Đề trong bộ</strong>.</li><li>Bấm <strong>Thêm đề</strong>.</li><li>Popup hiển thị danh sách đề có thể thêm — bao gồm: <ul><li><a href="./de-mau-luyen-thi">Đề mẫu Luyện thi</a> (HSA / TSA / TNTHPT)</li><li><a href="./de-on-khoa-hoc">Đề ôn khóa học</a></li><li><a href="./danh-gia-dau-vao">Đánh giá đầu vào</a></li></ul></li><li>Lọc theo Loại đề / Môn / Năm thi.</li><li>Tick chọn các đề muốn thêm → bấm <strong>Thêm vào bộ</strong>.</li><li>Trong tab Đề trong bộ: <ul><li><strong>Kéo-thả</strong> sắp xếp thứ tự.</li><li>Cấu hình <strong>luật làm</strong>: bắt buộc làm theo thứ tự / cho phép làm bất kỳ thứ tự.</li><li><strong>Hạn nộp riêng</strong> từng đề (nếu khác hạn chung của bộ).</li><li><strong>Bỏ đề</strong> khỏi bộ.</li></ul></li><li>Bấm <strong>Lưu</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Sắp xếp thứ tự đề trong bộ theo lộ trình ôn luyện. Vd với bộ &quot;Luyện thi HSA&quot;:</p><ol><li>Đề khởi động (mức Nhận biết).</li><li>Đề tăng tốc (Thông hiểu - Vận dụng).</li><li>Đề thực chiến (full đề + đếm giờ chặt).</li></ol></div><h2 id="cau-hinh-bo-đe" tabindex="-1">Cấu hình bộ đề <a class="header-anchor" href="#cau-hinh-bo-đe" aria-label="Permalink to “Cấu hình bộ đề”">​</a></h2><p>Trong chi tiết bộ, tab <strong>Cấu hình</strong>:</p><table tabindex="0"><thead><tr><th>Cấu hình</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Bắt buộc làm theo thứ tự</strong></td><td>Phải làm đề 1 xong mới mở đề 2</td></tr><tr><td><strong>Điểm tối thiểu để qua đề</strong></td><td>Phải đạt điểm này mới mở đề kế (khi bắt buộc thứ tự)</td></tr><tr><td><strong>Hiển thị tiến độ bộ</strong></td><td>Hiển thị thanh tiến độ &quot;3/10 đề hoàn thành&quot; cho học viên</td></tr><tr><td><strong>Cấp chứng chỉ khi hoàn thành</strong></td><td>Tự cấp chứng chỉ khi học viên hoàn thành cả bộ với điểm trung bình ≥ ngưỡng</td></tr><tr><td><strong>Số lần làm lại tối đa từng đề</strong></td><td>Áp dụng đồng loạt cho mọi đề trong bộ (override cấu hình đề lẻ)</td></tr></tbody></table><h2 id="gan-bo-đe" tabindex="-1">Gán bộ đề <a class="header-anchor" href="#gan-bo-đe" aria-label="Permalink to “Gán bộ đề”">​</a></h2><p>Sau khi cấu hình xong, <strong>giao bộ</strong> cho học viên:</p><h3 id="gan-cho-khoa-hoc" tabindex="-1">Gán cho khóa học <a class="header-anchor" href="#gan-cho-khoa-hoc" aria-label="Permalink to “Gán cho khóa học”">​</a></h3><ol><li>Vào tab <strong>Phân phối</strong> → <strong>Gán cho khóa</strong>.</li><li>Chọn 1 hoặc nhiều khóa.</li><li>Học viên đã mua khóa sẽ tự thấy bộ trong tab &quot;Đề thi&quot; của khóa.</li></ol><h3 id="gan-cho-lop-hoc" tabindex="-1">Gán cho lớp học <a class="header-anchor" href="#gan-cho-lop-hoc" aria-label="Permalink to “Gán cho lớp học”">​</a></h3><ol><li>Tab <strong>Phân phối</strong> → <strong>Gán cho lớp</strong>.</li><li>Chọn các lớp.</li><li>Học viên trong lớp nhận bộ.</li></ol><h3 id="gan-cho-hoc-vien-cu-the" tabindex="-1">Gán cho học viên cụ thể <a class="header-anchor" href="#gan-cho-hoc-vien-cu-the" aria-label="Permalink to “Gán cho học viên cụ thể”">​</a></h3><ol><li>Tab <strong>Phân phối</strong> → <strong>Gán cho học viên</strong>.</li><li>Chọn từng học viên hoặc upload danh sách Excel email/SĐT.</li><li>Học viên thấy bộ trong tab &quot;Đề thi&quot; cá nhân.</li></ol><h3 id="cong-khai" tabindex="-1">Công khai <a class="header-anchor" href="#cong-khai" aria-label="Permalink to “Công khai”">​</a></h3><ol><li>Tab <strong>Phân phối</strong> → bật <strong>Công khai</strong>.</li><li>Mọi học viên có quyền tương ứng (HSA/TSA/THPT) đều thấy.</li></ol><h2 id="sua-bo-đe" tabindex="-1">Sửa bộ đề <a class="header-anchor" href="#sua-bo-đe" aria-label="Permalink to “Sửa bộ đề”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Sửa</strong>.</li><li>Cập nhật tên, cấu hình.</li><li>Thêm/bỏ đề trong tab <strong>Đề trong bộ</strong>.</li><li>Bấm <strong>Lưu</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Khi học viên đã bắt đầu làm bộ:</p><ul><li>Thêm đề mới vào bộ → OK, học viên thấy đề mới.</li><li>Bỏ đề khỏi bộ → học viên không thấy đề đó nữa, nhưng kết quả cũ vẫn giữ.</li><li>Đổi thứ tự / cấu hình &quot;bắt buộc thứ tự&quot; → có thể làm học viên đang dở bị khóa, hãy cẩn thận.</li></ul></div><h2 id="xoa-bo-đe" tabindex="-1">Xóa bộ đề <a class="header-anchor" href="#xoa-bo-đe" aria-label="Permalink to “Xóa bộ đề”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Xóa</strong>.</li><li>Xác nhận.</li></ol><div class="danger custom-block"><p class="custom-block-title custom-block-title-default">DANGER</p><p>Xóa bộ chỉ xóa <strong>nhóm/đóng gói</strong>. Các đề bên trong <strong>vẫn còn</strong> trong hệ thống. Việc gán bộ cho học viên sẽ bị hủy.</p></div><h2 id="nhan-ban-bo-đe" tabindex="-1">Nhân bản bộ đề <a class="header-anchor" href="#nhan-ban-bo-đe" aria-label="Permalink to “Nhân bản bộ đề”">​</a></h2><p>Khi cần tạo đợt mới với cấu trúc tương tự:</p><ol><li>Tại dòng bộ gốc, bấm <strong>Nhân bản</strong>.</li><li>Bộ mới có hậu tố &quot;(Bản sao)&quot;.</li><li>Đổi tên (vd từ &quot;Thi thử đợt 1&quot; → &quot;Thi thử đợt 2&quot;).</li><li>Trong tab Đề trong bộ, <strong>thay</strong> các đề cũ bằng đề mới của đợt 2.</li><li>Lưu.</li></ol><h2 id="theo-doi-ket-qua-bo-đe" tabindex="-1">Theo dõi kết quả bộ đề <a class="header-anchor" href="#theo-doi-ket-qua-bo-đe" aria-label="Permalink to “Theo dõi kết quả bộ đề”">​</a></h2><ol><li>Mở chi tiết bộ → tab <strong>Kết quả</strong>.</li><li>Bảng tổng quan: <ul><li>Mỗi học viên: số đề đã làm / tổng số đề trong bộ.</li><li><strong>Điểm trung bình</strong> trên tất cả đề đã làm.</li><li><strong>Trạng thái</strong>: Đang làm / Hoàn thành / Bỏ dở.</li></ul></li><li>Bấm vào học viên → xem chi tiết điểm từng đề.</li><li><strong>Xuất Excel</strong> danh sách kết quả.</li><li><strong>Biểu đồ tiến độ cả bộ</strong>: bao nhiêu % học viên đã làm xong, phân bố điểm trung bình.</li></ol><h2 id="cap-chung-chi-hoan-thanh-bo" tabindex="-1">Cấp chứng chỉ hoàn thành bộ <a class="header-anchor" href="#cap-chung-chi-hoan-thanh-bo" aria-label="Permalink to “Cấp chứng chỉ hoàn thành bộ”">​</a></h2><p>Nếu bật <strong>Cấp chứng chỉ khi hoàn thành</strong> trong cấu hình:</p><ul><li>Khi học viên hoàn thành <strong>tất cả đề trong bộ</strong> với điểm trung bình ≥ ngưỡng → hệ thống tự cấp chứng chỉ.</li><li>Chứng chỉ là <strong>file PDF</strong> học viên tải xuống được, mang logo trung tâm, số chứng chỉ, ngày cấp.</li><li>Mẫu chứng chỉ cấu hình ở phần Quản trị → Mẫu chứng chỉ (nếu có).</li></ul><h2 id="nhap-xuat" tabindex="-1">Nhập / Xuất <a class="header-anchor" href="#nhap-xuat" aria-label="Permalink to “Nhập / Xuất”">​</a></h2><ul><li><strong>Xuất Excel</strong> danh sách bộ đề.</li><li><strong>Xuất chi tiết bộ</strong> (file Word/PDF): tải về toàn bộ đề trong bộ — hữu ích khi muốn in giấy cho thi tổ chức tập trung.</li><li><strong>Xuất kết quả</strong> từ tab Kết quả → file Excel danh sách điểm.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Một đề có thể thuộc nhiều bộ không?</strong> → Có. Đề là đơn vị độc lập, bộ chỉ là &quot;tham chiếu&quot;. 1 đề HSA có thể nằm trong cả &quot;Bộ luyện HSA cơ bản&quot; và &quot;Bộ thi thử HSA tháng 5&quot;.</p><p><strong>Học viên làm xong đề trong bộ thì đề riêng lẻ có tự đánh dấu hoàn thành không?</strong> → Có. Hệ thống ghi nhận lượt làm đề ở mức <strong>đề thi</strong>, dùng chung cho mọi nơi tham chiếu đề đó (bộ, khóa, lớp).</p><p><strong>Tôi muốn tạo bộ chỉ chứa các đề Toán TNTHPT cho lớp 12A1.</strong> → Tạo bộ &quot;Bộ đề Toán TNTHPT - 12A1&quot;, thêm các đề Toán đã tạo, <strong>gán cho lớp 12A1</strong> ở tab Phân phối.</p><p><strong>Học viên đã làm 5/10 đề rồi xin đổi sang bộ khác - dữ liệu cũ có giữ không?</strong> → Có. Kết quả từng đề vẫn lưu trong hồ sơ học viên. Khi gán bộ mới, nếu bộ mới có chứa đề học viên đã làm rồi, hệ thống hiển thị &quot;Đã hoàn thành&quot; sẵn.</p><p><strong>Cấp chứng chỉ tự động có an toàn không? Sợ học viên gian lận điểm.</strong> → Bật <strong>Số lần làm tối đa</strong> thấp, <strong>không hiển thị đáp án ngay sau khi nộp</strong> để giảm khả năng học vẹt. Có thể yêu cầu <strong>xác thực thi giám sát</strong> với các đề trọng yếu.</p><p><strong>Có quản lý nhiều &quot;đợt&quot; trong cùng một bộ không?</strong> → Không, mỗi bộ là 1 đơn vị độc lập. Mỗi đợt nên tạo 1 bộ riêng (Đợt 1, Đợt 2…). Có thể dùng <strong>Nhân bản</strong> để tạo nhanh.</p><p><strong>Bộ này có gắn được vào trang bán hàng để khách mua riêng không?</strong> → Hiện bộ đề là công cụ <strong>giao việc nội bộ</strong>, không bán trực tiếp. Nếu muốn bán &quot;gói đề thi&quot;, hãy tạo một <a href="./khoa-hoc">Khóa học</a> loại &quot;Luyện đề thực chiến&quot; và gắn bộ vào khóa đó.</p><p><strong>Tôi muốn 1 bộ đề gồm cả đề HSA và đề TSA - được không?</strong> → Được. Chọn <strong>Loại bộ = Hỗn hợp</strong> khi tạo. Khi thêm đề, có thể chọn tự do cả HSA và TSA. Lưu ý: thông báo rõ cho học viên về tính chất hỗn hợp để khỏi nhầm.</p>',55)])])}const u=n(a,[["render",l]]);export{d as __pageData,u as default};
